SELECT baseline."in.geometry_building_type_recs" AS geometry_building_type_recs, sum(1) AS sample_count, sum(baseline.weight) AS units_count, sum(baseline."out.electricity.total.energy_consumption" * baseline.weight) AS "electricity.total.energy_consumption__baseline", sum(CASE WHEN (upgrade.applicability = true) THEN upgrade."out.electricity.total.energy_consumption" ELSE baseline."out.electricity.total.energy_consumption" END * baseline.weight) AS "electricity.total.energy_consumption__upgrade" FROM (SELECT * FROM resstock_2024_amy2018_release_2_metadata WHERE resstock_2024_amy2018_release_2_metadata.upgrade = 0) AS baseline LEFT OUTER JOIN (SELECT * FROM resstock_2024_amy2018_release_2_metadata WHERE resstock_2024_amy2018_release_2_metadata.upgrade != 0) AS upgrade ON baseline.bldg_id = upgrade.bldg_id AND upgrade.upgrade = 1 AND upgrade.applicability = true WHERE baseline.applicability = true AND baseline."in.state" = 'CO' GROUP BY 1 ORDER BY 1